<?php include __DIR__.'/_init.php'; $s=current_student();
if($_SERVER['REQUEST_METHOD']==='POST'){ if(!verify_csrf($_POST['csrf_token']??'')) die('CSRF'); $quizId=(int)$_POST['quiz_id']; $qs=$db->prepare('SELECT q.id,q.marks FROM quiz_questions q WHERE q.quiz_id=?');$qs->execute([$quizId]);$questions=$qs->fetchAll();$score=0;$max=0;$answers=[];
foreach($questions as $q){$max+=$q['marks'];$ans=(int)($_POST['q_'.$q['id']]??0);$answers[$q['id']]=$ans;$ok=$db->prepare('SELECT is_correct FROM quiz_options WHERE id=? AND question_id=?');$ok->execute([$ans,$q['id']]);if((int)$ok->fetchColumn()===1)$score+=$q['marks'];}
$percent=$max?round(($score/$max)*100,2):0; $quiz=$db->prepare('SELECT passing_marks FROM quizzes WHERE id=?');$quiz->execute([$quizId]);$pass=(int)$percent >= (int)$quiz->fetchColumn();
$db->prepare('INSERT INTO quiz_attempts(quiz_id,student_id,score,passed,answers_json,attempted_at) VALUES(?,?,?,?,?,NOW())')->execute([$quizId,$s['id'],$percent,$pass?1:0,json_encode($answers)]); flash('success',"Quiz submitted. Score: {$percent}%"); redirect('/student/quizzes.php'); }
$quizzes=$db->query("SELECT * FROM quizzes WHERE status='published'")->fetchAll();
?>
<h2>Quizzes</h2><?php if($m=flash('success')) echo '<p>'.$m.'</p>'; foreach($quizzes as $z): $qs=$db->prepare('SELECT * FROM quiz_questions WHERE quiz_id=? ORDER BY sort_order');$qs->execute([$z['id']]);$questions=$qs->fetchAll();?><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input type="hidden" name="quiz_id" value="<?=$z['id']?>"><h4><?=e($z['title'])?></h4><?php foreach($questions as $q):?><p><?=e($q['question'])?></p><?php $ops=$db->prepare('SELECT * FROM quiz_options WHERE question_id=?');$ops->execute([$q['id']]);foreach($ops as $o):?><label><input type="radio" name="q_<?=$q['id']?>" value="<?=$o['id']?>" required> <?=e($o['option_text'])?></label><br><?php endforeach; endforeach;?><button>Submit Quiz</button></form><hr><?php endforeach; ?><h3>My Quiz Results</h3><?php $a=$db->prepare('SELECT qa.*,q.title FROM quiz_attempts qa JOIN quizzes q ON q.id=qa.quiz_id WHERE qa.student_id=? ORDER BY qa.id DESC');$a->execute([$s['id']]);foreach($a as $r):?><div><?=e($r['title'])?> - <?=e($r['score'])?>% - <?= $r['passed']?'Pass':'Fail'?></div><?php endforeach;?>
